/**
 * Drawing-bar icon registry
 *
 * mapping keys come in two flavours:
 *   1. klinecharts overlay name (e.g. 'horizontalStraightLine') — used as the
 *      overlay `name` passed to klinecharts AND looked up here for the icon.
 *   2. TV icon / control name (e.g. 'cursorGroup', 'ruler') — used only for
 *      group-header buttons and toolbar controls.
 *
 * Every value is the zero-arg arrow function generated by generate-icons.mjs.
 */

