// ---------------------------------------------------------------------------
// DrawingToolItem — extended SelectDataSourceItem for the drawing bar groups.
// ---------------------------------------------------------------------------
export interface DrawingToolItem {
  /** klinecharts overlay name to create — OR 'cursor'/'eraser' for mode changes */
  key: string
  /** Icon name override. Falls back to `key` if omitted. */
  iconKey?: string
  /** Display label */
  text: string
  /** true → resets to cursor/crosshair mode (no overlay created) */
  isCursorMode?: boolean
  /** true → toggles eraser/delete mode (no overlay created) */
  isEraserMode?: boolean
  /** Data passed to the overlay's extendData (e.g. emoji text for simpleAnnotation) */
  extendData?: unknown
}

// ---------------------------------------------------------------------------
// Group factory functions
// ---------------------------------------------------------------------------

/** Group 1 — Cursor / pointer tools */
export function createCursorOptions(locale: string): DrawingToolItem[] {
  return [
    { key: 'cursor',      iconKey: 'cursor',      text: i18n('cursor', locale),      isCursorMode: true },
    { key: 'circle',      iconKey: 'dotMarker',   text: i18n('dot', locale) },
    { key: 'arrow',       iconKey: 'arrowMarker', text: i18n('arrow', locale) },
    { key: 'brush',       iconKey: 'brushPath',   text: i18n('brush', locale) },
    { key: 'eraser',      iconKey: 'eraser',      text: i18n('eraser', locale),      isEraserMode: true },
  ]
}

