// ---------------------------------------------------------------------------
// Icon component
// ---------------------------------------------------------------------------
interface IconProps {
  /** Icon name — a key in `mapping`. Falls back to nothing if not found. */
  name: string
  className?: string
}

export const Icon: FC<IconProps> = ({ name }) => {
  const IconFn = mapping[name] as (() => any) | undefined
  return IconFn ? IconFn() : null
}
